class efuAI {
    constructor() {
        this.config = GLOBAL_CONFIG.post_ai;        // 全局AI配置
        this.scoGPTIsRunning = false;               // 是否有AI进程正在运行
    }

    /**
     * 初始化功能，设置必要的配置并可能启动AI生成
     */
    init() {
        if (!document.querySelector(".ai-explanation")) return;
        this.scoGPTIsRunning = false;
        this.aiPostExplanation = PAGE_CONFIG.ai_text ? PAGE_CONFIG.ai_text + "" : false;
        if (!this.aiPostExplanation) {
            this.generate();
        } else {
            this.aiShowAnimation(Promise.resolve(this.aiPostExplanation));
        }
        this.AIEngine();
    }

    /**
     * 从页面中提取标题和内容
     */
    getTitleAndContent() {
        const e = document.getElementById("article-container");
        const t = document.title;
        const n = e.getElementsByTagName("p");
        const i = e.querySelectorAll("h1, h2, h3, h4, h5");
        return (t + " " + Array.from(i).concat(Array.from(n)).map((e) => e.innerText.replace(/https?:\/\/[^\s]+/g, "")).join(" ")).slice(0, 1000);
    }

    /**
     * 触发AI生成解释内容的过程
     */
    async generate() {
        this.aiShowAnimation(this.callChatGPTAPI(document.title, this.getTitleAndContent()));
    }

    /**
     * 调用ChatGPT API获取生成的解释
     */
    async callChatGPTAPI(title, content) {
        const apiKey = this.config.apiKey;
        const apiUrl = this.config.apiUrl;
        const model = this.config.model;
        const maxTokens = this.config.max_tokens;
        const prompt = `Title: ${title}\nContent: ${content}\nPlease provide a summary.`;

        try {
            const response = await fetch(apiUrl, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Authorization': `Bearer ${apiKey}`
                },
                body: JSON.stringify({
                    model: model,
                    prompt: prompt,
                    max_tokens: maxTokens,
                    temperature: 0.7
                })
            });

            if (!response.ok) {
                throw new Error(`Request failed with status ${response.status}`);
            }

            const data = await response.json();
            return data.choices[0].text.trim();
        } catch (error) {
            console.error("Request failed:", error.message);
            return error.message;
        }
    }

    /**
     * 显示AI内容生成的动画效果
     */
    aiShowAnimation(e, t = false) {
        const n = document.querySelector(".ai-explanation");
        const i = document.querySelector(".ai-tag");
        if (!n || this.scoGPTIsRunning) return;
        this.scoGPTIsRunning = true;
        this.cleanSuggestions();
        i.classList.add("loadingAI");
        n.style.display = "block";
        n.innerHTML = '生成中...<span class="blinking-cursor"></span>';
        let s, o, a = true, c = 0, r = true;
        const l = new IntersectionObserver((e) => {
            a = e[0].isIntersecting;
            if (a) requestAnimationFrame(o);
        }, { threshold: 0 });
        e.then((e) => {
            s = performance.now();
            o = () => {
                if (c < e.length && a) {
                    const r = performance.now();
                    const g = r - s;
                    const h = e.slice(c, c + 1);
                    const u = /[，。！、？,.!?]/.test(h);
                    const m = /[a-zA-Z0-9]/.test(h);
                    if (g >= (u ? 100 * Math.random() + 100 : m ? 10 : 25)) {
                        n.innerText = e.slice(0, c + 1);
                        s = r;
                        c++;
                        if (c < e.length) n.innerHTML = e.slice(0, c) + '<span class="blinking-cursor"></span>';
                        else {
                            n.innerHTML = e;
                            n.style.display = "block";
                            this.scoGPTIsRunning = false;
                            i.classList.remove("loadingAI");
                            l.disconnect();
                            if (t) this.createSuggestions();
                        }
                        if (a) requestAnimationFrame(o);
                    }
                }
            };
            if (a && r) setTimeout(() => {
                requestAnimationFrame(o);
                r = false;
            }, 3000);
            l.observe(n);
        }).catch((e) => {
            console.error("Failed to retrieve information:", e);
            n.innerHTML = "检索信息失败";
            n.style.display = "block";
            this.scoGPTIsRunning = false;
            i.classList.remove("loadingAI");
            l.disconnect();
        });
    }

    /**
     * 设置AI交互的入口点
     */
    AIEngine() {
        const e = document.querySelector(".ai-tag");
        e && e.addEventListener("click", () => {
            if (!this.scoGPTIsRunning) {
                this.aiTalkMode = true;
                this.aiShowAnimation(Promise.resolve(this.config.talk), true);
            }
        });
    }

    /**
     * 清理建议区域
     */
    cleanSuggestions() {
        const e = document.querySelector(".ai-suggestions");
        e ? e.innerHTML = "" : console.error("Element '.ai-suggestions' not found");
    }

    /**
     * 创建交互建议项
     */
    createSuggestions() {
        if (this.aiTalkMode) {
            this.cleanSuggestions();
            this.createSuggestionItemWithAction("这篇文章讲了什么？", () => {
                this.aiPostExplanation === "" ? this.generate() : this.aiShowAnimation(Promise.resolve(this.aiPostExplanation), true);
            });
            if (this.config.randomPost) this.createSuggestionItemWithAction("带我去看看其他文章", () => toRandomPost());
            this.aiTalkMode = true;
        }
    }

    /**
     * 创建带动作的建议项
     */
    createSuggestionItemWithAction(e, t) {
        const n = document.querySelector(".ai-suggestions");
        if (!n) {
            console.error("Unable to find an element with class 'ai-suggestions'");
            return;
        }
        const i = document.createElement("div");
        i.classList.add("ai-suggestions-item");
        i.textContent = e;
        i.addEventListener("click", t);
        n.appendChild(i);
    }
}

// 实例化 efuAI 类
const efu_ai = new efuAI();